23	  results: QuoteResult[];
24	}
25	
26	const PROCESSING_FEE = 5;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
42	
43	const componentGroupPremium = (count: number, type: string): number =>
44	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumFor(type);
45	
46	const itemSurcharges = (item: Item): number => {
47	  const base = basePremiumFor(item.type);
48	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
49	  const enchantmentSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
50	  return curseSurcharge + enchantmentSurcharge;
51	};
52	
53	const countComponentsByType = (items: Item[]): Map<string, number> => {
54	  const counts = new Map<string, number>();
55	  for (const item of items) {
56	    if (COMPONENT_TYPES.has(item.type)) {
57	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
58	    }
59	  }
60	  return counts;
61	};
62	
63	const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }): number => {
64	  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
65	  const componentCounts = countComponentsByType(items);
66	
67	  const standardBasePremium = standardItems.reduce(
68	    (sum, item) => sum + basePremiumFor(item.type),
69	    0,
70	  );
71	
72	  const totalComponentPremium = [...componentCounts].reduce(
73	    (sum, [type, count]) => sum + componentGroupPremium(count, type),
74	    0,
75	  );
76	
77	  const policyBasePremium = standardBasePremium + totalComponentPremium;
78	
79	  const totalItemSurcharges = standardItems.reduce(
80	    (sum, item) => sum + itemSurcharges(item),
81	    0,
82	  );
83	
84	  const firstInsuranceSurcharge = policyBasePremium * 0.1;
85	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
86	
87	  return Math.ceil(
88	    policyBasePremium + totalItemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
89	  );
90	};
91	
92	export function processScenario(scenario: Scenario): ScenarioOutput {
93	  const results = scenario.steps.map((step) => ({
94	    premium: calculateQuotePremium(step.items, scenario.customer),
95	  }));
96	  return { results };
97	}
